import{c as t,Q as o,j as a,m as r}from"./chunks/framework.BXc4yaFE.js";const c=JSON.parse('{"title":"You prompt (the new) Claude wrong. Do this instead: — @rubenhassid","description":"","frontmatter":{"title":"You prompt (the new) Claude wrong. Do this instead: — @rubenhassid","author":"Ruben Hassid（@rubenhassid）","date":"2026-05-10T00:00:00.000Z","source":"https://x.com/rubenhassid/status/2053324202321834073","type":"tweet"},"headers":[],"relativePath":"research/tweets/2026-05-10-@rubenhassid-834073.md","filePath":"research/tweets/2026-05-10-@rubenhassid-834073.md","lastUpdated":1779894392000}'),s={name:"research/tweets/2026-05-10-@rubenhassid-834073.md"};function i(n,e,l,h,p,d){return o(),a("div",null,[...e[0]||(e[0]=[r('<h1 id="you-prompt-the-new-claude-wrong-do-this-instead-—-rubenhassid" tabindex="-1">You prompt (the new) Claude wrong. Do this instead: — @rubenhassid <a class="header-anchor" href="#you-prompt-the-new-claude-wrong-do-this-instead-—-rubenhassid" aria-label="Permalink to &quot;You prompt (the new) Claude wrong. Do this instead: — @rubenhassid&quot;">​</a></h1><p><strong>來源</strong>：<a href="https://x.com/rubenhassid/status/2053324202321834073" target="_blank" rel="noreferrer">https://x.com/rubenhassid/status/2053324202321834073</a><strong>作者</strong>：Ruben Hassid（@rubenhassid） <strong>發布日期</strong>：2026-05-10 <strong>收錄日期</strong>：2026-05-10 <strong>類型</strong>：Twitter Article <strong>統計</strong>：114 likes · 15 retweets · 316 bookmarks · 90881 views</p><hr><h2 id="全文" tabindex="-1">全文 <a class="header-anchor" href="#全文" aria-label="Permalink to &quot;全文&quot;">​</a></h2><p>Claude is the best AI.</p><p>And Claude&#39;s best model is Opus 4.7.</p><p>The better you prompt it, the better results you get.</p><p><strong>Anthropic, Claude Parent&#39;s company, just wrote a 31-page PDF on prompting 4.7. Prompting the new Claude is drastically different than the old one.</strong></p><p>But if you read my newsletter, it&#39;s because you don&#39;t want to read a 31-page-long document on how to prompt. I feel you.</p><p>So I spent the weekend on it for you to easily know:</p><ul><li>How to prompt Claude 4.7</li><li>How <em>not</em> to prompt Claude 4.7</li></ul><p>Before starting, I want you to do two things:</p><ol><li><strong>Save this</strong> &amp; block 20 minutes this week to try Claude.</li><li><strong>Share</strong> it with anyone who is looking for an easy guide on prompting Claude.</li></ol><hr><h1 id="i-old-claude-vs-new-claude" tabindex="-1">I - Old Claude vs. New Claude. <a class="header-anchor" href="#i-old-claude-vs-new-claude" aria-label="Permalink to &quot;I - Old Claude vs. New Claude.&quot;">​</a></h1><p>The new Claude is Opus 4.7. A reminder on where to find it:</p><p>This is how to prompt the new Claude:</p><h2 id="step-1-replace-review-with-the-actual-scope" tabindex="-1">Step 1: Replace &quot;review&quot; with the actual scope. <a class="header-anchor" href="#step-1-replace-review-with-the-actual-scope" aria-label="Permalink to &quot;Step 1: Replace &quot;review&quot; with the actual scope.&quot;">​</a></h2><p><strong>Before (4.6):</strong> Claude would try to understand what you meant, with freedom. <strong>After (4.7):</strong> Does exactly what you typed.</p><p><strong>Old:</strong></p><blockquote><p>Review this contract.</p></blockquote><p><strong>New:</strong></p><blockquote><p>Review this contract. Flag risks per clause. Rate severity 1-5. Suggest one rewrite per risky clause. Return as a table.</p></blockquote><p><strong>The fix:</strong> Name every output. Name the order. Name the boundaries.</p><h2 id="step-2-define-length" tabindex="-1">Step 2: Define length. <a class="header-anchor" href="#step-2-define-length" aria-label="Permalink to &quot;Step 2: Define length.&quot;">​</a></h2><p><strong>Before (4.6):</strong> Roughly the same length each time, regardless of input size. <strong>After (4.7):</strong> Sizes the answer to what it thinks the task is. Long input + &quot;summarize&quot; = long summary. If you want a short summary, be explicit.</p><p><strong>Old:</strong></p><blockquote><p>Summarize this report.</p></blockquote><p><strong>New:</strong></p><blockquote><p>Summarize this report in exactly 5 bullet points. Each bullet under 15 words. First word of each bullet: an action verb.</p></blockquote><p><strong>The fix:</strong> Name the format and the cap.</p><h2 id="step-3-use-positive-instructions-only" tabindex="-1">Step 3: Use positive instructions only. <a class="header-anchor" href="#step-3-use-positive-instructions-only" aria-label="Permalink to &quot;Step 3: Use positive instructions only.&quot;">​</a></h2><p>Negative instructions stick to the literal sentence on Claude 4.7.</p><p>They don&#39;t work. (<em>it&#39;s kinda funny to say &quot;don&#39;t be negative&quot; which is negative</em>).</p><p><strong>Old:</strong></p><blockquote><p>Don&#39;t use jargon. Don&#39;t use buzzwords. Don&#39;t sound like a marketer.</p></blockquote><p><strong>New:</strong></p><blockquote><p>Write in plain English a 16-year-old could read aloud. Use short, concrete words: simple, specific, real. Replace &quot;leverage&quot; with &quot;use.&quot; Replace &quot;scalable&quot; with &quot;works at any size.&quot;</p></blockquote><h2 id="step-4-use-action-verbs-only" tabindex="-1">Step 4: Use action verbs only. <a class="header-anchor" href="#step-4-use-action-verbs-only" aria-label="Permalink to &quot;Step 4: Use action verbs only.&quot;">​</a></h2><p>Each action verb tells Claude 4.7 to ship something specific. And 4.7 loves that.</p><p><strong>Old:</strong></p><blockquote><p>Can you help me with the email?</p></blockquote><p><strong>New:</strong></p><blockquote><p>Go to my Gmail. Find [contact] and read our last conversation. Write the answer email. Final draft. Send-ready. Goal: book a meeting with the CRO of Snowflake by Friday. Length: under 90 words. Tone: confident, casual, specific.</p></blockquote><p><em>You need to use Claude Connector for this, to connect your apps like Gmail to Claude.</em><em>My next article is about Claude Connectors.</em></p><h2 id="step-5-calling-tools" tabindex="-1">Step 5: Calling &quot;tools&quot;. <a class="header-anchor" href="#step-5-calling-tools" aria-label="Permalink to &quot;Step 5: Calling &quot;tools&quot;.&quot;">​</a></h2><p>A &quot;tool&quot; is, for example, when Claude goes to the web to find information.</p><p><strong>Before (4.6):</strong> Called tools frequently. <strong>After (4.7):</strong> Calls fewer tools. Reasons more between calls.</p><p><strong>The fix:</strong></p><ul><li>If quality is good, trust the new default.</li><li>If you want more tool use, prompt explicitly. For example:</li></ul><blockquote><p>Use web search aggressively. Verify every claim with at least 2 sources.</p></blockquote><h2 id="step-6-the-new-tone" tabindex="-1">Step 6: The new tone. <a class="header-anchor" href="#step-6-the-new-tone" aria-label="Permalink to &quot;Step 6: The new tone.&quot;">​</a></h2><p><strong>Before (4.6):</strong> Warmer. Validation-forward. &quot;Great question!&quot; energy. More emojis. <strong>After (4.7):</strong> More direct. Less validation. Almost zero emojis.</p><p><strong>The fix</strong> <em>(if you want a warmer tone back)</em>:</p><blockquote><p>Use a warm, conversational tone. Acknowledge the user&#39;s framing before answering.</p></blockquote><p>Even better: paste 2-3 sentences in the voice you want, and tell Claude to match the rhythm of those examples. Or build your about-me file before (here&#39;s how).</p><h2 id="step-7-add-go-beyond-the-basics-on-creative-tasks" tabindex="-1">Step 7: Add &quot;go beyond the basics&quot; on creative tasks. <a class="header-anchor" href="#step-7-add-go-beyond-the-basics-on-creative-tasks" aria-label="Permalink to &quot;Step 7: Add &quot;go beyond the basics&quot; on creative tasks.&quot;">​</a></h2><p>This phrase is from Anthropic&#39;s own Claude 4.7 doc. It pushes 4.7 past the literal minimum on creative or open-ended work. Feels great when you finally try it!</p><p><strong>Old:</strong></p><blockquote><p>Build a landing page for my AI consultancy.</p></blockquote><p><strong>New:</strong></p><blockquote><p>Build a landing page for my AI consultancy.</p><p>Sections (in this order):</p><ul><li>Hero (headline + subheadline + CTA)</li><li>Logo bar (6 client placeholders)</li><li>3 case-study cards (problem / what I did / result)</li><li>Service blocks (workshops, deployment, sprints, fractional Chief of AI)</li><li>Testimonial carousel (3 quotes)</li><li>About me (180-word bio + headshot placeholder)</li><li>Newsletter signup</li><li>Footer</li></ul><p>Style: editorial, serif headlines, sans-serif body, generous whitespace. Animations: subtle on scroll. No purple gradients.</p><p>Go beyond the basics. Polish like it&#39;s a real client deliverable.</p></blockquote><hr><h1 id="ii-the-trick-to-bypass-adaptive-thinking" tabindex="-1">II - The trick to bypass adaptive thinking. <a class="header-anchor" href="#ii-the-trick-to-bypass-adaptive-thinking" aria-label="Permalink to &quot;II - The trick to bypass adaptive thinking.&quot;">​</a></h1><p>Models like Claude have a &quot;thinking&quot; mode in which they think before answering. This gives you much better answers every single time.</p><p>But the new Claude does not reason by default. They call it &quot;adaptive thinking&quot;.</p><p>Here&#39;s a <em>trick</em> to make sure Claude always uses the maximum reasoning:</p><p>The prompt trick at the end: <strong>&quot;Think before answering (maximum reasoning)&quot;</strong>.</p><hr><h1 id="iii-have-a-claude-skill-to-prompt-for-you" tabindex="-1">III - Have a Claude /skill to prompt for you. <a class="header-anchor" href="#iii-have-a-claude-skill-to-prompt-for-you" aria-label="Permalink to &quot;III - Have a Claude /skill to prompt for you.&quot;">​</a></h1><p>A &quot;skill&quot; in Claude is a command with tons of instructions pre-built.</p><p><em>I wrote a newsletter on Claude Skills right here.</em></p><p>And I made a skill to turn any lazy prompt into an Opus 4.7-optimized one.</p><p>Here&#39;s an example:</p><p>Then Claude will use my skill and think about the answer:</p><p>You can easily copy the new prompt:</p><p>And then paste it in a new chat:</p><p>And click on the new form it generated:</p><p>If you also want this skill, follow these instructions:</p><ol><li>Download my skill → <strong>here</strong> (and use the <strong>password</strong>: HOW-TO-AI).</li><li>Then upload the skill inside Claude.</li><li>Once done, just type <strong>/47</strong>.</li></ol><p>Here&#39;s the visual explanation, step-by-step:</p><hr><p>PS: I made this website to help people start with Claude → claude101.com.</p><p>Claude101 is a list of all of my favorite Claude guides. They are all free.</p><p>You can share this too with your network → it&#39;s simple: <strong>claude101.com</strong></p><hr><h1 id="a-message-from-the-author-ruben" tabindex="-1">A message from the author, Ruben. <a class="header-anchor" href="#a-message-from-the-author-ruben" aria-label="Permalink to &quot;A message from the author, Ruben.&quot;">​</a></h1><p>This article exists because 78,000+ people decided AI is too important to leave aside. Not only that, but they shared it around them. They understand they are the sum of the 5 people around them. So better have them using AI.</p><p>If this helped you — or if it&#39;ll help someone you know — forward it to them. That&#39;s how this grew. Just readers like you sending it to people like them.</p><p>And if you&#39;re new here, follow me on X → @rubenhassid (also free!)</p><hr><h2 id="研究摘要" tabindex="-1">研究摘要 <a class="header-anchor" href="#研究摘要" aria-label="Permalink to &quot;研究摘要&quot;">​</a></h2><p><strong>TL;DR</strong>：Claude 4.7（Opus）比 4.6 更字面執行指令，需要明確定義輸出格式、長度、正向語氣、action verb，並加「Think before answering (maximum reasoning)」觸發完整推理。</p><h3 id="核心論點" tabindex="-1">核心論點 <a class="header-anchor" href="#核心論點" aria-label="Permalink to &quot;核心論點&quot;">​</a></h3><ol><li><strong>Claude 4.7 字面執行</strong>：4.6 會自行詮釋模糊指令；4.7 嚴格照字面執行，需要完整指定輸出結構（名稱、順序、邊界）</li><li><strong>長度必須明確聲明</strong>：4.7 根據任務規模自動調整回應長度，不想要長篇須明確指定格式上限</li><li><strong>正向指令優先</strong>：負向指令（Don&#39;t X）在 4.7 效果不佳；需改寫為正向替代行為（Do Y instead）</li><li><strong>工具呼叫減少</strong>：4.7 默認減少 tool call、增加推理；若需要多工具調用須明確指示</li><li><strong>「go beyond the basics」</strong>：Anthropic 官方文件認可的 phrase，可推動 4.7 在創意任務突破字面最低要求</li></ol><h3 id="關鍵數據-工具" tabindex="-1">關鍵數據 / 工具 <a class="header-anchor" href="#關鍵數據-工具" aria-label="Permalink to &quot;關鍵數據 / 工具&quot;">​</a></h3><ul><li>Claude Opus 4.7（目標模型）、Claude 4.6（對照組）</li><li>關鍵 phrase：「Think before answering (maximum reasoning)」</li><li>關鍵 phrase：「Go beyond the basics. Polish like it&#39;s a real client deliverable.」</li><li>Claude Connector（gmail 等應用整合功能，Claude.ai 平台限定）</li><li>作者自製 <code>/47</code> skill（Dropbox 下載，密碼 HOW-TO-AI）</li></ul><h3 id="批判性觀察" tabindex="-1">批判性觀察 <a class="header-anchor" href="#批判性觀察" aria-label="Permalink to &quot;批判性觀察&quot;">​</a></h3><ol><li><strong>無量化驗證</strong>：所有 before/after 差異均為定性描述，缺乏 A/B 測試數據；「Does exactly what you typed」是主觀觀察而非實測結論</li><li><strong>Claude Code CLI 適用性有限</strong>：Gmail Connector 等步驟 4 範例僅適用 Claude.ai 網頁平台，在 cc-workspace CLI 環境不適用；需篩選</li><li><strong>基礎知識密度低</strong>：多數技巧（具體輸出定義、正向語氣、格式聲明）是 prompt engineering 公認常識；對有經驗的使用者新增資訊量有限</li></ol><hr><h2 id="評分" tabindex="-1">評分 <a class="header-anchor" href="#評分" aria-label="Permalink to &quot;評分&quot;">​</a></h2><table tabindex="0"><thead><tr><th>維度</th><th>分數</th><th>說明</th></tr></thead><tbody><tr><td>A. Workspace 可行動性 (30%)</td><td>7/10</td><td>步驟 1-4、6-7 可直接套用於 cc-workspace prompt 設計；step 4 的 Gmail Connector 在 CLI 環境不適用</td></tr><tr><td>B. 創新性 (20%)</td><td>5/10</td><td>Adaptive thinking bypass trick 和 4.7 工具呼叫行為差異有新意；其餘為 prompt engineering 基礎常識</td></tr><tr><td>C. 證據品質 (20%)</td><td>4/10</td><td>無實驗數據或 benchmark；所有 4.6 vs 4.7 比較均為定性觀察，缺乏可重現驗證</td></tr><tr><td>D. 技術深度 (15%)</td><td>5/10</td><td>有具體 before/after 範例可參照；但對 adaptive thinking 機制解釋停留在表面現象</td></tr><tr><td>E. 泛化性 (15%)</td><td>7/10</td><td>步驟 1-3、6-7 跨任務類型通用（技術文件、runbook、分析報告均適用）</td></tr><tr><td><strong>加權總分</strong></td><td><strong>5.7/10</strong></td><td>7×0.3 + 5×0.2 + 4×0.2 + 5×0.15 + 7×0.15 = 2.1+1.0+0.8+0.75+1.05</td></tr></tbody></table><p><strong>整合決策</strong>：Skip（總分 5.7 ≤ 6） <strong>理由</strong>：內容多為 prompt engineering 通用常識，缺乏量化驗證，且部分內容（Claude Connector）限定 Claude.ai 平台，在 cc-workspace CLI 環境適用性有限</p>',103)])])}const g=t(s,[["render",i]]);export{c as __pageData,g as default};
